mapper.select:
/* com.shop.mapper.PartnerVendor.selectPartnerVendorListPaging */ SELECT ROW_NUMBER() OVER(ORDER BY A.ID DESC) AS no, A.ID AS id, A.PARTNER_ID AS partnerId, A.VENDOR_NM AS vendorNm, A.LOCATION AS location, A.PHONE_NO AS phoneNo, A.PHONE_NO2 AS phoneNo2, A.KAKAO_ID AS kakaoId, A.ETC_INFO AS etcInfo, A.CRE_TM AS creTm, A.UPD_TM AS updTm, COALESCE((SELECT X.USER_NM FROM TB_USER X WHERE A.CRE_USER = X.LOGIN_ID), A.CRE_USER) AS creUser, A.UPD_USER AS updUser, COUNT(*) OVER() AS totalRowCount, (SELECT COUNT(X.ID) AS prodCnt FROM TB_PRODUCT X WHERE X.VENDOR_ID = A.ID) AS prodCnt FROM TB_PARTNER_VENDOR A WHERE A.DEL_YN = 'N'
AND A.PARTNER_ID = #{filter.partnerId}
AND A.VENDOR_NM LIKE CONCAT('%', #{filter.vendorNm}, '%')
AND (A.PHONE_NO LIKE CONCAT('%', #{filter.phoneNo}, '%') OR A.PHONE_NO2 LIKE CONCAT('%', #{filter.phoneNo}, '%'))
ORDER BY A.ID DESC LIMIT #{pageRowCount} OFFSET (#{curPage} - 1) * #{pageRowCount}

/* com.shop.mapper.PartnerVendor.selectPartnerVendorById */
SELECT

FROM TB_PARTNER_VENDOR
WHERE ID = #{id}
AND DEL_YN = 'N'

