    PARTNER_ID, VENDOR_NM, LOCATION, PHONE_NO, PHONE_NO2, KAKAO_ID, ETC_INFO,
    DEL_YN, CRE_USER, CRE_TM, UPD_USER, UPD_TM
) VALUES (
    #{partnerId}, #{vendorNm}, #{location}, #{phoneNo}, #{phoneNo2}, #{kakaoId}, #{etcInfo},
    'N', #{creUser}, NOW(), #{updUser}, NOW()
)

